def test_profile_explain_lists_profiles_and_policy_packs():
    runner = CliRunner()

    result = runner.invoke(app, ["profile-explain"])

    assert result.exit_code == 0
    assert "Project profiles:" in result.output
    assert "generic-git-repo" in result.output
    assert "python-cli" in result.output
    assert "governance-wrapper" in result.output
    assert "Policy packs:" in result.output
    assert "starter" in result.output
    assert "agentic-development" in result.output
    assert "output-contracts" in result.output


def test_workflow_status_reports_idle(tmp_path):
    runner = CliRunner()
    root = tmp_path / "repo"
    (root / ".agentic").mkdir(parents=True)
    (root / ".agentic" / "workflow_state").write_text("IDLE\n", encoding="utf-8")

    result = runner.invoke(app, ["workflow", "status", "--root", str(root)])

    assert result.exit_code == 0, result.output
    assert "workflow_state=IDLE" in result.output
    assert "current_work=missing" in result.output


def test_workflow_request_sets_current_work_requested_from_idle(tmp_path):
    runner = CliRunner()
    root = tmp_path / "repo"
    (root / ".agentic").mkdir(parents=True)
    (root / ".agentic" / "workflow_state").write_text("IDLE\n", encoding="utf-8")
    (root / ".agentic" / "current_work.yaml").write_text("name: demo\nsteps: []\n", encoding="utf-8")

    result = runner.invoke(app, ["workflow", "request", "--root", str(root)])

    assert result.exit_code == 0, result.output
    assert "Workflow request state: REQUESTED" in result.output
    assert "Next state: IDLE" in result.output
    assert (root / ".agentic" / "workflow_state").read_text(encoding="utf-8") == "IDLE\n"
    assert "state: REQUESTED" in (root / ".agentic" / "current_work.yaml").read_text(encoding="utf-8")


